const req = $('Webhook Debug').first().json.body || {};
const msgs = $('Stats Mensagens').first().json;
const sess = $('Stats Sessoes').first().json;
const agentes = $('Stats Agentes').all().map(i => i.json);

const agora = new Date().toISOString();
const janela = req.janela_horas || 2;

const alertas = [];
if (parseInt(msgs.mensagens_recentes) === 0) {
  alertas.push({ nivel: 'WARN', msg: `Nenhuma mensagem nas ultimas ${janela}h — pipeline pode estar inativo` });
}
if (parseInt(sess.sem_agente) > 0) {
  alertas.push({ nivel: 'WARN', msg: `${sess.sem_agente} sessoes sem agente_humano_id — numeros sem agente vinculado` });
}
if (msgs.ultima_mensagem) {
  const diff = (Date.now() - new Date(msgs.ultima_mensagem).getTime()) / 60000;
  if (diff > 60) alertas.push({ nivel: 'INFO', msg: `Ultima mensagem ha ${Math.round(diff)} minutos` });
}

return [{ json: {
  gerado_em: agora,
  janela_horas: janela,
  filtro_numero: req.numero_whatsapp || null,
  status_pipeline: alertas.some(a => a.nivel === 'WARN') ? 'ATENCAO' : 'OK',
  alertas,
  mensagens: {
    total: parseInt(msgs.total_mensagens),
    recentes: parseInt(msgs.mensagens_recentes),
    ultima: msgs.ultima_mensagem,
    audios: parseInt(msgs.audios),
    textos: parseInt(msgs.textos),
    contatos_unicos: parseInt(msgs.contatos_unicos)
  },
  sessoes: {
    total: parseInt(sess.total_sessoes),
    ativas: parseInt(sess.sessoes_ativas),
    sem_agente: parseInt(sess.sem_agente),
    com_agente: parseInt(sess.com_agente),
    ultima_atualizacao: sess.ultima_atualizacao
  },
  agentes
}}];
